package src.blocks.faces.org.apache.cocoon.faces.taglib;

public class ValidateLengthTag extends ValidatorTag { private String minimum ; private String maximum ; public void setMaximum ( String maximum ) { this . maximum = maximum ; } public void setMinimum ( String minimum ) { this . minimum = minimum ; } public int doStartTag ( String namespaceURI , String localName , String qName , Attributes atts ) throws SAXException { super . setValidatorId ( "javax.faces.Length" ) ; return super . doStartTag ( namespaceURI , localName , qName , atts ) ; } protected Validator createValidator ( ) { final UIComponentTag tag = FacesUtils . findParentUIComponentTag ( this ) ; LengthValidator validator = ( LengthValidator ) super . createValidator ( ) ; if ( maximum != null ) { validator . setMaximum ( tag . evaluateInteger ( maximum ) ) ; } if ( minimum != null ) { validator . setMinimum ( tag . evaluateInteger ( minimum ) ) ; } return validator ; } public void recycle ( ) { super . recycle ( ) ; this . minimum = null ; this . maximum = null ; } }